'use client';

import { useEffect, useState } from 'react';
import Link from 'next/link';
import {
  getProjects, getTasks, getMeetings, getActionItems, seedDemoData,
  type Project, type Task, type Meeting, type ActionItem
} from '@/lib/store';

export default function DashboardPage() {
  const [projects, setProjects] = useState<Project[]>([]);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [meetings, setMeetings] = useState<Meeting[]>([]);
  const [actionItems, setActionItems] = useState<ActionItem[]>([]);
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    seedDemoData();
    setProjects(getProjects());
    setTasks(getTasks());
    setMeetings(getMeetings());
    setActionItems(getActionItems());
    setMounted(true);
  }, []);

  if (!mounted) return null;

  const activeTasks = tasks.filter(t => t.status === 'in_progress');
  const openActions = actionItems.filter(a => a.status !== 'done');
  const upcomingMeetings = meetings.filter(m => m.status === 'scheduled');
  const activeProjects = projects.filter(p => p.status === 'active');

  const formatDate = (d: string) => {
    if (!d) return '';
    const date = new Date(d);
    const now = new Date();
    const diff = date.getTime() - now.getTime();
    const days = Math.ceil(diff / 86400000);
    if (days === 0) return 'Idag';
    if (days === 1) return 'Imorgon';
    if (days < 7) return `Om ${days} dagar`;
    return date.toLocaleDateString('sv-SE', { day: 'numeric', month: 'short' });
  };

  return (
    <>
      <header className="page-header">
        <div>
          <h2>Dashboard</h2>
          <p className="page-header-subtitle">Översikt av alla dina arbetsflöden</p>
        </div>
        <div style={{ display: 'flex', gap: 'var(--space-sm)' }}>
          <Link href="/meetings?new=1" className="btn btn-primary">
            🎙️ Nytt möte
          </Link>
          <Link href="/transcribe" className="btn btn-secondary">
            📝 Transkribera
          </Link>
        </div>
      </header>

      <div className="page-body">
        {/* Stats */}
        <div className="stats-grid">
          <div className="card animate-in">
            <div className="card-header">
              <span className="card-title">📁 Aktiva Projekt</span>
            </div>
            <div className="card-stat accent">{activeProjects.length}</div>
            <p style={{ fontSize: '0.8rem', color: 'var(--text-tertiary)', marginTop: '4px' }}>
              {projects.filter(p => p.status === 'planning').length} under planering
            </p>
          </div>
          <div className="card animate-in" style={{ animationDelay: '50ms' }}>
            <div className="card-header">
              <span className="card-title">📋 Pågående Tasks</span>
            </div>
            <div className="card-stat" style={{ color: 'var(--color-info)' }}>{activeTasks.length}</div>
            <p style={{ fontSize: '0.8rem', color: 'var(--text-tertiary)', marginTop: '4px' }}>
              {tasks.filter(t => t.status === 'backlog').length} i backlog
            </p>
          </div>
          <div className="card animate-in" style={{ animationDelay: '100ms' }}>
            <div className="card-header">
              <span className="card-title">✅ Öppna Actions</span>
            </div>
            <div className="card-stat warning">{openActions.length}</div>
            <p style={{ fontSize: '0.8rem', color: 'var(--text-tertiary)', marginTop: '4px' }}>
              {openActions.filter(a => a.priority === 'high').length} med hög prioritet
            </p>
          </div>
          <div className="card animate-in" style={{ animationDelay: '150ms' }}>
            <div className="card-header">
              <span className="card-title">🎙️ Kommande Möten</span>
            </div>
            <div className="card-stat success">{upcomingMeetings.length}</div>
            <p style={{ fontSize: '0.8rem', color: 'var(--text-tertiary)', marginTop: '4px' }}>
              {meetings.filter(m => m.status === 'completed').length} avslutade
            </p>
          </div>
        </div>

        {/* Content Grid */}
        <div className="content-grid">
          {/* Projekt */}
          <div className="card animate-in" style={{ animationDelay: '200ms' }}>
            <div className="card-header">
              <span className="card-title">📁 Projekt</span>
              <Link href="/projects" className="btn btn-ghost btn-sm">Visa alla →</Link>
            </div>
            <div>
              {projects.map(project => (
                <Link href={`/projects/${project.id}`} key={project.id} className="list-item" style={{ textDecoration: 'none', color: 'inherit' }}>
                  <div style={{ width: 10, height: 10, borderRadius: '50%', background: project.color, flexShrink: 0 }} />
                  <div className="list-item-content">
                    <div className="list-item-title">{project.name}</div>
                    <div className="list-item-subtitle">{project.description}</div>
                  </div>
                  <span className={`badge ${project.status === 'active' ? 'badge-success' : project.status === 'planning' ? 'badge-info' : 'badge-accent'}`}>
                    {project.status === 'active' ? 'Aktiv' : project.status === 'planning' ? 'Planering' : 'Avslutad'}
                  </span>
                </Link>
              ))}
            </div>
          </div>

          {/* Action Items */}
          <div className="card animate-in" style={{ animationDelay: '250ms' }}>
            <div className="card-header">
              <span className="card-title">✅ Action Items</span>
              <Link href="/actions" className="btn btn-ghost btn-sm">Visa alla →</Link>
            </div>
            <div>
              {openActions.length === 0 ? (
                <div className="empty-state">
                  <p>Inga öppna action items 🎉</p>
                </div>
              ) : openActions.slice(0, 5).map(item => (
                <div key={item.id} className="list-item">
                  <div className={`priority-indicator priority-${item.priority}`} />
                  <div className="list-item-content">
                    <div className="list-item-title">{item.title}</div>
                    <div className="list-item-subtitle">
                      {item.assignee && `${item.assignee} · `}
                      {item.dueDate && formatDate(item.dueDate)}
                    </div>
                  </div>
                  <span className={`badge ${item.priority === 'high' ? 'badge-danger' : item.priority === 'medium' ? 'badge-warning' : 'badge-info'}`}>
                    {item.priority === 'high' ? 'Hög' : item.priority === 'medium' ? 'Medium' : 'Låg'}
                  </span>
                </div>
              ))}
            </div>
          </div>

          {/* Upcoming Meetings */}
          <div className="card animate-in" style={{ animationDelay: '300ms' }}>
            <div className="card-header">
              <span className="card-title">🎙️ Kommande Möten</span>
              <Link href="/meetings" className="btn btn-ghost btn-sm">Visa alla →</Link>
            </div>
            <div>
              {upcomingMeetings.length === 0 ? (
                <div className="empty-state">
                  <p>Inga kommande möten</p>
                </div>
              ) : upcomingMeetings.map(meeting => {
                const project = projects.find(p => p.id === meeting.projectId);
                return (
                  <Link href={`/meetings/${meeting.id}`} key={meeting.id} className="list-item" style={{ textDecoration: 'none', color: 'inherit' }}>
                    <span style={{ fontSize: '1.4rem' }}>📅</span>
                    <div className="list-item-content">
                      <div className="list-item-title">{meeting.title}</div>
                      <div className="list-item-subtitle">
                        {formatDate(meeting.scheduledAt)} · {meeting.participants.join(', ')}
                        {project && ` · ${project.name}`}
                      </div>
                    </div>
                    <span className="badge badge-info">Planerat</span>
                  </Link>
                );
              })}
            </div>
          </div>

          {/* Recent Activity */}
          <div className="card animate-in" style={{ animationDelay: '350ms' }}>
            <div className="card-header">
              <span className="card-title">⚡ Senaste Aktivitet</span>
            </div>
            <div>
              {activeTasks.slice(0, 4).map(task => {
                const project = projects.find(p => p.id === task.projectId);
                return (
                  <div key={task.id} className="list-item">
                    <span style={{ fontSize: '1.1rem' }}>🔄</span>
                    <div className="list-item-content">
                      <div className="list-item-title">{task.title}</div>
                      <div className="list-item-subtitle">
                        {project?.name} · {task.assignee || 'Otilldelad'}
                        {task.dueDate && ` · ${formatDate(task.dueDate)}`}
                      </div>
                    </div>
                    <span className="badge badge-accent">Pågår</span>
                  </div>
                );
              })}
            </div>
          </div>
        </div>
      </div>
    </>
  );
}
