// ── Generic Helpers ──

function genId(): string {
  return Date.now().toString(36) + Math.random().toString(36).substr(2, 9);
}

function getAll<T>(key: string): T[] {
  if (typeof window === 'undefined') return [];
  const raw = localStorage.getItem(key);
  return raw ? JSON.parse(raw) : [];
}

function saveAll<T>(key: string, items: T[]): void {
  localStorage.setItem(key, JSON.stringify(items));
}

function createItem<T extends { id: string; createdAt: string }>(
  key: string,
  data: Omit<T, 'id' | 'createdAt'>
): T {
  const items = getAll<T>(key);
  const item = { ...data, id: genId(), createdAt: new Date().toISOString() } as T;
  items.push(item);
  saveAll(key, items);
  return item;
}

function updateItem<T extends { id: string }>(key: string, id: string, updates: Partial<T>): T | null {
  const items = getAll<T>(key);
  const idx = items.findIndex(i => i.id === id);
  if (idx === -1) return null;
  items[idx] = { ...items[idx], ...updates, updatedAt: new Date().toISOString() } as T;
  saveAll(key, items);
  return items[idx];
}

function deleteItem<T extends { id: string }>(key: string, id: string): boolean {
  const items = getAll<T>(key);
  const filtered = items.filter(i => i.id !== id);
  if (filtered.length === items.length) return false;
  saveAll(key, filtered);
  return true;
}

function getItem<T extends { id: string }>(key: string, id: string): T | undefined {
  return getAll<T>(key).find(i => i.id === id);
}

