export const createMeeting = (data: Omit<Meeting, 'id' | 'createdAt' | 'transcript'>) =>
  createItem<Meeting>('uwa_meetings', { ...data, transcript: [] } as Omit<Meeting, 'id' | 'createdAt'>);
export const updateMeeting = (id: string, u: Partial<Meeting>) => updateItem<Meeting>('uwa_meetings', id, u);
export const addTranscriptSegment = (meetingId: string, segment: TranscriptSegment) => {
  const meeting = getMeeting(meetingId);
  if (!meeting) return;
  meeting.transcript.push(segment);
  updateMeeting(meetingId, { transcript: meeting.transcript });
};

